code = """import json

sql_result = locals()['var_function-call-14191286052941678138']
mongo_result = locals()['var_function-call-16206363852773393884']

# Ensure mongo_result is a list (it might be a file path if I was wrong, but the error suggested it's a list)
if isinstance(mongo_result, str):
    with open(mongo_result, 'r') as f:
        mongo_result = json.load(f)

ref_counts = {row['business_ref']: row['review_cnt'] for row in sql_result}

category_counts = {}

def extract_categories(desc):
    if not desc:
        return []
    desc = desc.strip()
    if desc.endswith('.'):
        desc = desc[:-1]
    
    phrases = [
        "services in ",
        "including ", 
        "destination for ",
        "seeking "
    ]
    
    last_pos = -1
    used_phrase = ""
    
    for p in phrases:
        pos = desc.rfind(p)
        if pos > last_pos:
            last_pos = pos
            used_phrase = p
            
    if last_pos != -1:
        cat_str = desc[last_pos + len(used_phrase):]
        cats = [c.strip() for c in cat_str.split(',')]
        if cats:
            last = cats[-1]
            if last.lower().startswith('and '):
                cats[-1] = last[4:].strip()
        return cats
    return []

for bus in mongo_result:
    bid = bus['business_id']
    bref = bid.replace('businessid_', 'businessref_')
    
    if bref in ref_counts:
        count = ref_counts[bref]
        cats = extract_categories(bus.get('description', ''))
        
        for cat in cats:
            category_counts[cat] = category_counts.get(cat, 0) + count

sorted_cats = sorted(category_counts.items(), key=lambda x: x[1], reverse=True)
top5 = sorted_cats[:5]

print('__RESULT__:')
print(json.dumps([c[0] for c in top5]))"""

